{
  "mode": "method",
  "tests": [
    {
      "name": "valid_jwt_token",
      "input": {
        "token": "valid.jwt.token",
        "authSecret": "your_auth_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": true,
        "user": {
          "id": "123",
          "role": "admin"
        }
      },
      "notes": "Tests valid JWT token verification with correct secret and issuer."
    },
    {
      "name": "invalid_jwt_token",
      "input": {
        "token": "invalid.jwt.token",
        "authSecret": "your_auth_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": false,
        "error": "Invalid token"
      },
      "notes": "Tests handling of an invalid JWT token."
    },
    {
      "name": "expired_jwt_token",
      "input": {
        "token": "expired.jwt.token",
        "authSecret": "your_auth_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": false,
        "error": "Token expired"
      },
      "notes": "Tests handling of an expired JWT token."
    },
    {
      "name": "missing_auth_secret",
      "input": {
        "token": "valid.jwt.token",
        "authSecret": "",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": false,
        "error": "Missing AUTH_SECRET"
      },
      "notes": "Tests behavior when AUTH_SECRET is not provided."
    },
    {
      "name": "invalid_issuer",
      "input": {
        "token": "valid.jwt.token",
        "authSecret": "your_auth_secret",
        "validIssuers": ["https://invalidissuer.com"]
      },
      "output": {
        "isValid": false,
        "error": "Invalid issuer"
      },
      "notes": "Tests handling of a token with an invalid issuer."
    },
    {
      "name": "valid_m2m_token",
      "input": {
        "token": "valid.m2m.token",
        "authSecret": "your_auth_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": true,
        "user": {
          "id": "456",
          "role": "user"
        }
      },
      "notes": "Tests valid M2M token verification."
    },
    {
      "name": "no_token_provided",
      "input": {
        "token": "",
        "authSecret": "your_auth_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com"]
      },
      "output": {
        "isValid": false,
        "error": "No token provided"
      },
      "notes": "Tests behavior when no token is provided."
    },
    {
      "name": "multiple_valid_issuers",
      "input": {
        "token": "valid.jwt.token",
        "authSecret": "your_auth_secret",
        "validIssuers": ["https://issuer1.com", "https://issuer2.com", "https://issuer3.com"]
      },
      "output": {
        "isValid": true,
        "user": {
          "id": "789",
          "role": "editor"
        }
      },
